input.content:
:root {
  --bg: #0a0e1a;
  --panel: rgba(14, 20, 38, 0.78);
  --panel-border: rgba(120, 160, 255, 0.18);
  --accent: #ffb347;
  --accent2: #4fc3ff;
  --strike: #ff4d6d;
  --spare: #4fc3ff;
  --text: #eaf0ff;
  --muted: #8d9bc4;
  --good: #5be37a;
  font-family: "Segoe UI", system-ui, -apple-system, Roboto, Helvetica, Arial, sans-serif;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html,
body {
  height: 100%;
  overflow: hidden;
  background: var(--bg);
  color: var(--text);
  -webkit-user-select: none;
  user-select: none;
  touch-action: none;
}

#app {
  position: fixed;
  inset: 0;
}

#scene {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  cursor: grab;
}
#scene.grabbing {
  cursor: grabbing;
}

/* ---------- Overlays ---------- */
.overlay {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 18px;
  background: radial-gradient(
    ellipse at center,
    rgba(8, 12, 28, 0.82),
    rgba(4, 6, 16, 0.96)
  );
  backdrop-filter: blur(6px);
  z-index: 30;
  text-align: center;
  padding: 24px;
}
.overlay.hidden,
.hidden {
  display: none !important;
}

/* Loader */
.loader-ring {
  width: 64px;
  height: 64px;
  border: 5px solid rgba(255, 255, 255, 0.12);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 0.9s linear infinite;
}
.loader-text {
  color: var(--muted);
  letter-spacing: 0.12em;
  text-transform: uppercase;
  font-size: 13px;
}
@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* Start / Game over */
.title {
  font-size: clamp(46px, 11vw, 104px);
  font-weight: 900;
  letter-spacing: 0.04em;
  line-height: 0.95;
  background: linear-gradient(180deg, #fff, #9fb6ff);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  text-shadow: 0 10px 40px rgba(79, 195, 255, 0.25);
}
.title span {
  color: var(--accent);
  -webkit-text-fill-color: var(--accent);
}
.subtitle {
  color: var(--muted);
  font-size: 16px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}
.how-to {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin: 8px 0 6px;
  color: var(--muted);
  font-size: 14px;
  max-width: 480px;
}
.how-to b {
  color: var(--text);
}
.final-score {
  font-size: 28px;
  font-weight: 800;
  color: var(--accent);
}
.final-msg {
  color: var(--muted);
  font-size: 15px;
}

.btn-primary {
  margin-top: 10px;
  padding: 14px 38px;
  font-size: 17px;
  font-weight: 800;
  letter-spacing: 0.1em;
  color: #14213d;
  background: linear-gradient(180deg, var(--accent), #ff962b);
  border: none;
  border-radius: 999px;
  cursor: pointer;
  box-shadow: 0 8px 28px rgba(255, 150, 43, 0.4);
  transition: transform 0.12s ease, box-shadow 0.12s ease;
}
.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 36px rgba(255, 150, 43, 0.55);
}
.btn-primary:active {
  transform: translateY(0);
}

/* ---------- Scoreboard ---------- */
.hud-top {
  position: absolute;
  top: 12px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  align-items: stretch;
  gap: 8px;
  padding: 8px;
  background: var(--panel);
  border: 1px solid var(--panel-border);
  border-radius: 14px;
  backdrop-filter: blur(10px);
  z-index: 20;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.4);
  max-width: calc(100vw - 16px);
}
.sb-frames {
  display: flex;
  gap: 3px;
}
.frame {
  width: 46px;
  display: flex;
  flex-direction: column;
  border-radius: 8px;
  overflow: hidden;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.06);
  transition: border-color 0.2s, background 0.2s;
}
.frame.active {
  border-color: var(--accent);
  background: rgba(255, 179, 71, 0.1);
}
.frame.tenth {
  width: 62px;
}
.frame-num {
  font-size: 9px;
  color: var(--muted);
  text-align: center;
  padding: 2px 0 1px;
  letter-spacing: 0.05em;
}
.frame-rolls {
  display: flex;
  height: 18px;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
}
.roll {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  font-weight: 700;
  border-left: 1px solid rgba(255, 255, 255, 0.06);
}
.roll:first-child {
  border-left: none;
}
.roll.strike {
  color: var(--strike);
}
.roll.spare {
  color: var(--spare);
}
.frame-score {
  height: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  font-weight: 800;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  color: var(--text);
}
.sb-total {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 0 12px;
  border-left: 1px solid var(--panel-border);
  min-width: 64px;
}
.sb-total-label {
  font-size: 9px;
  color: var(--muted);
  letter-spacing: 0.15em;
}
.sb-total-value {
  font-size: 26px;
  font-weight: 900;
  color: var(--accent);
  line-height: 1;
}

/* ---------- Bottom controls ---------- */
.hud-bottom {
  position: absolute;
  bottom: 16px;
  left: 50%;
  transform: translateX(-50%);
  width: min(560px, calc(100vw - 24px));
  padding: 12px 16px 14px;
  background: var(--panel);
  border: 1px solid var(--panel-border);
  border-radius: 16px;
  backdrop-filter: blur(10px);
  z-index: 20;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.4);
}
.ctrl-row {
  display: flex;
  gap: 16px;
}
.ctrl-group {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 5px;
}
.ctrl-group label {
  font-size: 10px;
  letter-spacing: 0.15em;
  color: var(--muted);
}
.meter {
  position: relative;
  height: 10px;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.07);
  overflow: hidden;
}
.meter-fill {
  position: absolute;
  inset: 0;
  width: 0%;
  background: linear-gradient(90deg, var(--accent2), var(--accent));
  border-radius: 999px;
  transition: width 0.05s linear;
}
.meter.power .meter-fill {
  background: linear-gradient(90deg, #5be37a, #ffb347, #ff4d6d);
  width: 0%;
}
.meter-fill.spin {
  left: 50%;
  width: 0%;
  background: linear-gradient(90deg, var(--accent2), #b388ff);
}
.meter-marker {
  position: absolute;
  top: -2px;
  width: 3px;
  height: 14px;
  background: #fff;
  border-radius: 2px;
  left: 50%;
  transform: translateX(-50%);
  box-shadow: 0 0 6px rgba(255, 255, 255, 0.6);
}
.ctrl-hint {
  margin-top: 10px;
  text-align: center;
  font-size: 12px;
  color: var(--muted);
  letter-spacing: 0.03em;
  min-height: 15px;
}

/* ---------- Banner ---------- */
.banner {
  position: absolute;
  top: 36%;
  left: 50%;
  transform: translate(-50%, -50%) scale(0.6);
  font-size: clamp(40px, 12vw, 120px);
  font-weight: 900;
  letter-spacing: 0.06em;
  color: #fff;
  text-shadow: 0 0 30px rgba(255, 179, 71, 0.8), 0 8px 40px rgba(0, 0, 0, 0.6);
  pointer-events: none;
  z-index: 25;
  opacity: 0;
}
.banner.show {
  animation: bannerPop 1.8s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}
.banner.strike {
  color: var(--strike);
  text-shadow: 0 0 40px rgba(255, 77, 109, 0.9);
}
.banner.spare {
  color: var(--spare);
  text-shadow: 0 0 40px rgba(79, 195, 255, 0.9);
}
@keyframes bannerPop {
  0% {
    opacity: 0;
    transform: translate(-50%, -50%) scale(0.4) rotate(-6deg);
  }
  18% {
    opacity: 1;
    transform: translate(-50%, -50%) scale(1.12) rotate(2deg);
  }
  30% {
    transform: translate(-50%, -50%) scale(1) rotate(0deg);
  }
  78% {
    opacity: 1;
    transform: translate(-50%, -50%) scale(1) rotate(0deg);
  }
  100% {
    opacity: 0;
    transform: translate(-50%, -55%) scale(1.05);
  }
}

/* ---------- Ball picker ---------- */
.ball-picker {
  position: absolute;
  top: 50%;
  right: 14px;
  transform: translateY(-50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  padding: 10px 8px;
  background: var(--panel);
  border: 1px solid var(--panel-border);
  border-radius: 14px;
  backdrop-filter: blur(10px);
  z-index: 20;
}
.bp-label {
  font-size: 9px;
  letter-spacing: 0.15em;
  color: var(--muted);
}
.bp-swatches {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.swatch {
  width: 26px;
  height: 26px;
  border-radius: 50%;
  cursor: pointer;
  border: 2px solid transparent;
  box-shadow: inset -4px -4px 8px rgba(0, 0, 0, 0.5),
    inset 3px 3px 6px rgba(255, 255, 255, 0.25);
  transition: transform 0.12s, border-color 0.12s;
}
.swatch:hover {
  transform: scale(1.12);
}
.swatch.selected {
  border-color: #fff;
  transform: scale(1.12);
}

@media (max-width: 520px) {
  .frame {
    width: 34px;
  }
  .frame.tenth {
    width: 46px;
  }
  .roll {
    font-size: 10px;
  }
  .ball-picker {
    right: 6px;
  }
}

/**
 * scoring.js — Ten-pin bowling scoring engine.
 *
 * Implements full, correct ten-pin scoring including strike/spare bonuses
 * and the special rules of the 10th frame (up to 3 rolls). The scorer keeps
 * an ordered list of rolls (pin counts) and derives per-frame and cumulative
 * scores from them. This separation keeps the 3D/physics code free of any
 * scoring logic.
 */

export const TOTAL_FRAMES = 10;
export const TOTAL_PINS = 10;

export class BowlingGame {
  constructor() {
    this.reset();
  }

  reset() {
    /** Flat list of every roll's pin count, in order. */
    this.rolls = [];
    this.frameIndex = 0; // 0..9
    this.rollInFrame = 0; // which throw within the current frame
    this.pinsStandingInFrame = TOTAL_PINS;
    this.complete = false;
    this._frameStartRollIdx = [0]; // index into rolls[] where each frame begins
  }

  /** Is the game currently waiting for the first ball of a frame? */
  isFirstBallOfFrame() {
    return this.rollInFrame === 0;
  }

  get currentFrame() {
    return this.frameIndex;
  }

  /** Pins still standing on the lane for the active throw. */
  get pinsRemaining() {
    return this.pinsStandingInFrame;
  }

  /**
   * Record a throw that knocked down `pins` pins.
   * Returns an object describing what just happened so the UI can react.
   */
  roll(pins) {
    if (this.complete) return { ignored: true };
    pins = Math.max(0, Math.min(pins, this.pinsStandingInFrame));

    this.rolls.push(pins);
    const isTenth = this.frameIndex === TOTAL_FRAMES - 1;

    const result = {
      frame: this.frameIndex,
      pins,
      isStrike: false,
      isSpare: false,
      frameComplete: false,
      gameComplete: false,
      resetPins: false, // should all 10 pins be re-racked for the next throw?
    };

    if (!isTenth) {
      this._handleNormalFrame(pins, result);
    } else {
      this._handleTenthFrame(pins, result);
    }

    return result;
  }

  _handleNormalFrame(pins, result) {
    if (this.rollInFrame === 0) {
      if (pins === TOTAL_PINS) {
        // Strike — frame over, re-rack all pins.
        result.isStrike = true;
        result.frameComplete = true;
        result.resetPins = true;
        this._advanceFrame();
      } else {
        this.pinsStandingInFrame -= pins;
        this.rollInFrame = 1;
      }
    } else {
      // Second ball.
      const firstBall = TOTAL_PINS - this.pinsStandingInFrame;
      if (firstBall + pins === TOTAL_PINS) {
        result.isSpare = true;
      }
      result.frameComplete = true;
      result.resetPins = true;
      this._advanceFrame();
    }
  }

  _handleTenthFrame(pins, result) {
    const f = this._frameStartRollIdx[TOTAL_FRAMES - 1];
    const tenthRolls = this.rolls.slice(f);
    const n = tenthRolls.length;

    if (n === 1) {
      if (pins === TOTAL_PINS) {
        result.isStrike = true;
        result.resetPins = true;
        this.pinsStandingInFrame = TOTAL_PINS;
      } else {
        this.pinsStandingInFrame -= pins;
      }
      this.rollInFrame = 1;
    } else if (n === 2) {
      const [a, b] = tenthRolls;
      if (a === TOTAL_PINS) {
        // After an opening strike, the second ball is a fresh rack.
        if (b === TOTAL_PINS) {
          result.isStrike = true;
        }
        result.resetPins = true;
        this.pinsStandingInFrame = TOTAL_PINS - (b === TOTAL_PINS ? 0 : b);
        if (b === TOTAL_PINS) this.pinsStandingInFrame = TOTAL_PINS;
        this.rollInFrame = 2;
      } else if (a + b === TOTAL_PINS) {
        // Spare — earns a third ball with a fresh rack.
        result.isSpare = true;
        result.resetPins = true;
        this.pinsStandingInFrame = TOTAL_PINS;
        this.rollInFrame = 2;
      } else {
        // Open frame — game ends after two balls.
        this.pinsStandingInFrame -= pins;
        result.frameComplete = true;
        result.gameComplete = true;
        this.complete = true;
      }
    } else {
      // Third (bonus) ball — always ends the game.
      const [a] = tenthRolls;
      if (pins === TOTAL_PINS) result.isStrike = true;
      // (No spare flag possible to score on a bonus ball here.)
      result.frameComplete = true;
      result.gameComplete = true;
      this.complete = true;
    }
  }

  _advanceFrame() {
    this.frameIndex += 1;
    this.rollInFrame = 0;
    this.pinsStandingInFrame = TOTAL_PINS;
    if (this.frameIndex < TOTAL_FRAMES) {
      this._frameStartRollIdx[this.frameIndex] = this.rolls.length;
    }
  }

  /**
   * Compute per-frame and cumulative scores from the flat roll list.
   * Returns an array of 10 frame descriptors; bonus-dependent frames whose
   * bonus rolls haven't happened yet are left with `cumulative: null`.
   */
  getScorecard() {
    const frames = [];
    const r = this.rolls;
    let i = 0;
    let running = 0;
    let runningValid = true;

    for (let f = 0; f < TOTAL_FRAMES; f++) {
      const frame = { rolls: [], symbols: [], score: null, cumulative: null };

      if (i >= r.length) {
        frames.push(frame);
        continue;
      }

      if (f < TOTAL_FRAMES - 1) {
        if (r[i] === TOTAL_PINS) {
          // Strike.
          frame.rolls = [r[i]];
          frame.symbols = ["", "X"]; // displayed in the second box
          const bonus = (r[i + 1] ?? null) !== null && (r[i + 2] ?? null) !== null
            ? r[i + 1] + r[i + 2]
            : null;
          if (bonus !== null) {
            frame.score = 10 + bonus;
          }
          i += 1;
        } else {
          const a = r[i];
          const b = r[i + 1];
          frame.rolls = b === undefined ? [a] : [a, b];
          frame.symbols = [symFirst(a), b === undefined ? "" : symSecond(a, b)];
          if (b !== undefined) {
            if (a + b === TOTAL_PINS) {
              // Spare.
              const bonus = r[i + 2];
              if (bonus !== undefined) frame.score = 10 + bonus;
            } else {
              frame.score = a + b;
            }
            i += 2;
          }
          // else: frame incomplete, leave score null and stop consuming.
        }
      } else {
        // 10th frame: consume up to 3 rolls.
        const tenth = r.slice(i);
        frame.rolls = tenth;
        frame.symbols = tenthSymbols(tenth);
        const needed = tenthRollsNeeded(tenth);
        if (tenth.length >= needed && needed > 0) {
          frame.score = tenth.reduce((s, x) => s + x, 0);
        }
        i = r.length;
      }

      if (frame.score !== null && runningValid) {
        running += frame.score;
        frame.cumulative = running;
      } else if (frame.score === null) {
        runningValid = false;
      } else {
        running += frame.score;
        frame.cumulative = running;
      }

      frames.push(frame);
    }
    return frames;
  }

  /** Best known total (sums every frame that currently has a score). */
  getTotal() {
    return this.getScorecard().reduce((s, f) => s + (f.score ?? 0), 0);
  }
}

function symFirst(a) {
  if (a === 0) return "-";
  return String(a);
}
function symSecond(a, b) {
  if (b === 0) return "-";
  if (a + b === TOTAL_PINS) return "/";
  return String(b);
}
function tenthSymbols(rolls) {
  const out = [];
  let standing = TOTAL_PINS;
  for (let k = 0; k < rolls.length; k++) {
    const p = rolls[k];
    if (p === TOTAL_PINS && standing === TOTAL_PINS) {
      out.push("X");
      standing = TOTAL_PINS; // re-rack
    } else if (k > 0 && standing - p === 0 && out[k - 1] !== "X") {
      out.push("/");
      standing = TOTAL_PINS;
    } else {
      out.push(p === 0 ? "-" : String(p));
      standing -= p;
      if (standing <= 0) standing = TOTAL_PINS;
    }
  }
  return out;
}
function tenthRollsNeeded(rolls) {
  if (rolls.length === 0) return 3;
  const [a, b] = rolls;
  if (a === TOTAL_PINS) return 3; // strike → 3 balls
  if (b !== undefined && a + b === TOTAL_PINS) return 3; // spare → 3 balls
  return 2; // open frame
}

/**
 * physics.js — A compact, purpose-built physics simulator for bowling.
 *
 * Rather than pulling in a full rigid-body engine, this implements just what a
 * convincing bowling sim needs:
 *   - A rolling ball with velocity, angular momentum and a lateral "hook" force
 *     from spin (so curve/hook shots behave realistically on an oily lane).
 *   - Upright pins as capsule-ish cylinders that get knocked over by the ball
 *     and by each other (chain reactions), then tumble and slide off.
 *   - Gutters: the ball falls into the channel if it drifts past the lane edge.
 *
 * Units are meters. The lane runs along +Z (away from the bowler). X is the
 * lateral axis. Y is up.
 *
 * All vectors here are plain {x,y,z} objects to stay independent of Three.js;
 * the renderer reads positions/quaternions out each frame.
 */

export const LANE = {
  length: 18.29, // regulation ~60ft foul line to head pin + pin deck
  width: 1.05, // playing surface width (~41.5in)
  pinDeckZ: 16.7, // z of the head pin (#1)
  approachZ: 0.0, // foul line z (release point reference)
  gutterDepth: 0.12,
};

export const BALL_RADIUS = 0.108; // ~8.5in diameter
export const PIN_RADIUS = 0.06;
export const PIN_HEIGHT = 0.38;
const PIN_SPACING = 0.305; // 12 inches between pin centers

// Standard 10-pin triangle, offsets relative to the head pin (#1) at z = pinDeckZ.
// Row 1: pin 1; Row 2: 2,3; Row 3: 4,5,6; Row 4: 7,8,9,10
export const PIN_LAYOUT = [
  { id: 1, x: 0.0, z: 0.0 },
  { id: 2, x: -PIN_SPACING / 2, z: PIN_SPACING * 0.866 },
  { id: 3, x: PIN_SPACING / 2, z: PIN_SPACING * 0.866 },
  { id: 4, x: -PIN_SPACING, z: PIN_SPACING * 0.866 * 2 },
  { id: 5, x: 0.0, z: PIN_SPACING * 0.866 * 2 },
  { id: 6, x: PIN_SPACING, z: PIN_SPACING * 0.866 * 2 },
  { id: 7, x: -PIN_SPACING * 1.5, z: PIN_SPACING * 0.866 * 3 },
  { id: 8, x: -PIN_SPACING / 2, z: PIN_SPACING * 0.866 * 3 },
  { id: 9, x: PIN_SPACING / 2, z: PIN_SPACING * 0.866 * 3 },
  { id: 10, x: PIN_SPACING * 1.5, z: PIN_SPACING * 0.866 * 3 },
];

const GRAVITY = -9.8;

function v(x = 0, y = 0, z = 0) {
  return { x, y, z };
}
function len2(a) {
  return Math.hypot(a.x, a.z);
}

export class Pin {
  constructor(def) {
    this.id = def.id;
    this.home = v(def.x, PIN_HEIGHT / 2, LANE.pinDeckZ + def.z);
    this.reset();
  }
  reset() {
    this.pos = { ...this.home };
    this.vel = v();
    this.angVel = v(); // tumbling angular velocity (rad/s) about x/z axes
    this.tilt = v(); // accumulated rotation about x and z (radians)
    this.spin = 0; // spin about own vertical axis
    this.spinAngle = 0;
    this.down = false;
    this.settled = false;
    this.counted = false; // already tallied as knocked down
  }
  /** A pin counts as "down" once it tips past ~35° or leaves the deck. */
  get isKnocked() {
    return (
      this.down ||
      Math.abs(this.tilt.x) > 0.62 ||
      Math.abs(this.tilt.z) > 0.62 ||
      this.pos.y < PIN_HEIGHT * 0.35
    );
  }
}

export class BowlingPhysics {
  constructor() {
    this.pins = PIN_LAYOUT.map((d) => new Pin(d));
    this.resetBall();
    this.rolling = false;
    this.ballInGutter = false;
    this.settleTimer = 0;
  }

  resetPins() {
    for (const p of this.pins) p.reset();
  }

  /** Remove pins that were knocked down on a previous ball (deadwood cleared). */
  clearKnockedPins() {
    for (const p of this.pins) {
      if (p.isKnocked) {
        p.removed = true;
      }
    }
  }

  /** Restore a fresh full rack. */
  rackFull() {
    for (const p of this.pins) {
      p.reset();
      p.removed = false;
    }
  }

  resetBall(x = 0) {
    this.ball = {
      pos: v(x, BALL_RADIUS, LANE.approachZ - 0.4),
      vel: v(),
      angVel: v(), // rolling rotation (rad/s)
      spin: 0, // hook spin: + curves right, - curves left
      rollRot: v(), // accumulated rotation for rendering
    };
    this.ballInGutter = false;
  }

  /**
   * Launch the ball.
   * @param {number} power  0..1 → forward speed
   * @param {number} aimX   lateral release offset in meters (where on the lane)
   * @param {number} angle  initial heading in radians (small; + aims right)
   * @param {number} spin   hook spin -1..1 (curve strength + direction)
   */
  launch({ power, aimX, angle, spin }) {
    const speed = 7.5 + power * 7.5; // 7.5 .. 15 m/s
    this.ball.pos = v(aimX, BALL_RADIUS, LANE.approachZ - 0.2);
    this.ball.vel = v(Math.sin(angle) * speed, 0, Math.cos(angle) * speed);
    this.ball.spin = spin;
    this.ball.angVel = v(speed / BALL_RADIUS, spin * 6, 0);
    this.ball.rollRot = v();
    this.rolling = true;
    this.ballInGutter = false;
    this.settleTimer = 0;
  }

  step(dt) {
    if (this.rolling) this._stepBall(dt);
    this._stepPins(dt);

    // Determine when motion has effectively stopped.
    if (this.rolling) {
      const ballSlow =
        len2(this.ball.vel) < 0.25 ||
        this.ball.pos.z > LANE.pinDeckZ + 1.6 ||
        this.ballInGutter;
      const pinsCalm = this.pins.every(
        (p) => p.removed || len2(p.vel) < 0.05 || p.settled
      );
      if (ballSlow && pinsCalm) {
        this.settleTimer += dt;
      } else {
        this.settleTimer = 0;
      }
    }
  }

  _stepBall(dt) {
    const b = this.ball;
    const halfW = LANE.width / 2;

    // Gutter check — once the ball center passes the edge it drops into the channel.
    if (!this.ballInGutter && Math.abs(b.pos.x) > halfW - BALL_RADIUS * 0.5) {
      this.ballInGutter = true;
      b.spin = 0;
      // Clamp into the gutter trough and kill lateral motion.
      b.pos.x = Math.sign(b.pos.x) * (halfW + 0.04);
      b.vel.x = 0;
      b.vel.z = Math.max(b.vel.z * 0.7, 2.5);
    }

    if (this.ballInGutter) {
      b.pos.y = BALL_RADIUS - LANE.gutterDepth * 0.6;
      b.vel.z *= 1 - 0.5 * dt;
      b.pos.z += b.vel.z * dt;
      this._spinBallVisual(dt);
      return;
    }

    // Hook physics: spin imparts a growing lateral acceleration, stronger as the
    // ball slows and "grabs" the drier back end of the lane.
    const speed = len2(b.vel);
    const traction = Math.min(1, (16 - speed) / 12 + 0.15); // grows as it slows
    const hookAccel = b.spin * 9.0 * Math.max(0, traction);
    b.vel.x += hookAccel * dt;

    // Rolling friction — gradual slowdown.
    const friction = 0.86;
    b.vel.x -= b.vel.x * friction * dt * 0.25;
    b.vel.z -= b.vel.z * friction * dt * 0.18;

    // Integrate position.
    b.pos.x += b.vel.x * dt;
    b.pos.z += b.vel.z * dt;

    // Pin collisions.
    this._ballPinCollisions();

    this._spinBallVisual(dt);
  }

  _spinBallVisual(dt) {
    const b = this.ball;
    const speed = len2(b.vel);
    // Rolling: rotate about the axis perpendicular to travel.
    b.rollRot.x += (speed / BALL_RADIUS) * dt;
    b.rollRot.y += b.spin * 4 * dt;
  }

  _ballPinCollisions() {
    const b = this.ball;
    for (const p of this.pins) {
      if (p.removed) continue;
      const dx = p.pos.x - b.pos.x;
      const dz = p.pos.z - b.pos.z;
      const dist = Math.hypot(dx, dz);
      const minDist = BALL_RADIUS + PIN_RADIUS;
      if (dist < minDist && dist > 1e-4) {
        const nx = dx / dist;
        const nz = dz / dist;
        const impactSpeed = b.vel.x * nx + b.vel.z * nz;
        if (impactSpeed <= 0) continue;

        // Transfer momentum: pins are light, fly off energetically.
        const force = impactSpeed * 1.35;
        p.vel.x += nx * force + b.spin * 1.2;
        p.vel.z += nz * force;
        p.vel.y += 0.4 + Math.random() * 0.5; // little pop up
        // Tumble away from impact.
        p.angVel.x += nz * force * 4 * (0.8 + Math.random() * 0.4);
        p.angVel.z += -nx * force * 4 * (0.8 + Math.random() * 0.4);
        p.spin += (Math.random() - 0.5) * 8;
        p.down = true;

        // Ball slows and deflects slightly.
        b.vel.x -= nx * impactSpeed * 0.18;
        b.vel.z -= nz * impactSpeed * 0.12;
      }
    }
  }

  _stepPins(dt) {
    for (const p of this.pins) {
      if (p.removed || p.settled) continue;
      const moving =
        len2(p.vel) > 0.02 ||
        Math.abs(p.vel.y) > 0.02 ||
        Math.abs(p.angVel.x) > 0.05 ||
        Math.abs(p.angVel.z) > 0.05;
      if (!moving && !p.down) {
        continue; // still standing, untouched
      }

      // Gravity + vertical integration with floor bounce.
      p.vel.y += GRAVITY * dt;
      p.pos.y += p.vel.y * dt;
      const floor = PIN_HEIGHT / 2 - Math.min(0.18, Math.abs(p.tilt.x) + Math.abs(p.tilt.z)) * 0.1;
      if (p.pos.y < floor) {
        p.pos.y = floor;
        if (p.vel.y < 0) p.vel.y = -p.vel.y * 0.18;
        // Ground friction on lateral motion.
        p.vel.x *= 0.92;
        p.vel.z *= 0.92;
      }

      // Horizontal integration.
      p.pos.x += p.vel.x * dt;
      p.pos.z += p.vel.z * dt;

      // Tumble.
      p.tilt.x += p.angVel.x * dt;
      p.tilt.z += p.angVel.z * dt;
      p.spinAngle += p.spin * dt;
      // Damping on angular velocity.
      p.angVel.x *= 1 - 1.4 * dt;
      p.angVel.z *= 1 - 1.4 * dt;
      p.spin *= 1 - 0.8 * dt;

      // Pin-vs-pin collisions (chain reactions).
      this._pinPinCollisions(p);

      // Settle once it's lying down and slow.
      if (
        len2(p.vel) < 0.04 &&
        Math.abs(p.vel.y) < 0.05 &&
        (Math.abs(p.tilt.x) > 0.7 || Math.abs(p.tilt.z) > 0.7 || p.pos.y <= floor + 0.001)
      ) {
        if (p.isKnocked) {
          p.vel = v();
          p.settled = true;
        }
      }
    }
  }

  _pinPinCollisions(p) {
    for (const q of this.pins) {
      if (q === p || q.removed) continue;
      const dx = q.pos.x - p.pos.x;
      const dz = q.pos.z - p.pos.z;
      const dist = Math.hypot(dx, dz);
      const minDist = PIN_RADIUS * 2;
      if (dist < minDist && dist > 1e-4) {
        const nx = dx / dist;
        const nz = dz / dist;
        const overlap = minDist - dist;
        // Separate.
        p.pos.x -= nx * overlap * 0.5;
        p.pos.z -= nz * overlap * 0.5;
        q.pos.x += nx * overlap * 0.5;
        q.pos.z += nz * overlap * 0.5;

        const relSpeed = (p.vel.x - q.vel.x) * nx + (p.vel.z - q.vel.z) * nz;
        if (relSpeed > 0) {
          const transfer = relSpeed * 0.78;
          q.vel.x += nx * transfer;
          q.vel.z += nz * transfer;
          q.vel.y += 0.18 + Math.random() * 0.25;
          q.angVel.x += nz * transfer * 5 * (0.7 + Math.random() * 0.5);
          q.angVel.z += -nx * transfer * 5 * (0.7 + Math.random() * 0.5);
          q.spin += (Math.random() - 0.5) * 6;
          q.down = true;
          p.vel.x -= nx * transfer * 0.6;
          p.vel.z -= nz * transfer * 0.6;
        }
      }
    }
  }

  /** Count pins knocked down (for the current rack state). */
  countDownPins() {
    return this.pins.filter((p) => !p.removed && p.isKnocked).length;
  }

  /** True when ball + pins have come to rest after a roll. */
  isSettled() {
    return this.rolling && this.settleTimer > 0.7;
  }

  endRoll() {
    this.rolling = false;
  }
}

/**
 * scene.js — Three.js rendering layer for the bowling alley.
 *
 * Owns the scene graph (lane, gutters, pins, ball, environment, lighting) and
 * exposes update hooks the game loop calls with positions/rotations coming out
 * of the physics simulator. Knows nothing about scoring or input.
 */

import * as THREE from "three";
import {
  LANE,
  BALL_RADIUS,
  PIN_RADIUS,
  PIN_HEIGHT,
} from "./physics.js";

export const BALL_COLORS = [
  { name: "Fireball", hex: 0xe23636, accent: 0xff8a5c },
  { name: "Ocean", hex: 0x1f6fe0, accent: 0x6fd6ff },
  { name: "Venom", hex: 0x37c871, accent: 0xc6ff8a },
  { name: "Royal", hex: 0x8a4fff, accent: 0xd6b0ff },
  { name: "Onyx", hex: 0x1a1a22, accent: 0x4a4a66 },
  { name: "Sunset", hex: 0xff8c1a, accent: 0xffd56b },
];

export class BowlingScene {
  constructor(canvas) {
    this.canvas = canvas;
    this.renderer = new THREE.WebGLRenderer({
      canvas,
      antialias: true,
      alpha: false,
    });
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    this.renderer.shadowMap.enabled = true;
    this.renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    this.renderer.outputColorSpace = THREE.SRGBColorSpace;
    this.renderer.toneMapping = THREE.ACESFilmicToneMapping;
    this.renderer.toneMappingExposure = 1.05;

    this.scene = new THREE.Scene();
    this.scene.background = new THREE.Color(0x05060d);
    this.scene.fog = new THREE.Fog(0x05060d, 22, 40);

    this.camera = new THREE.PerspectiveCamera(50, 1, 0.1, 100);
    this._setBowlerCamera();

    this._buildLights();
    this._buildEnvironment();
    this._buildLane();
    this.pinMeshes = this._buildPins();
    this.ballMesh = this._buildBall(BALL_COLORS[0]);
    this.arrow = this._buildAimArrow();

    this._tmpQ = new THREE.Quaternion();
    this._tmpE = new THREE.Euler();

    this.resize();
    window.addEventListener("resize", () => this.resize());
  }

  // ---------- Camera presets ----------
  _setBowlerCamera() {
    this.camera.position.set(0, 1.6, -2.6);
    this.camera.lookAt(0, 0.6, LANE.pinDeckZ * 0.5);
    this.camFrom = this.camera.position.clone();
  }

  setCameraBowler() {
    this._lerpCamera(new THREE.Vector3(0, 1.6, -2.6), new THREE.Vector3(0, 0.6, LANE.pinDeckZ * 0.5));
  }
  setCameraFollow(ballZ, ballX) {
    const z = Math.min(ballZ - 3.2, LANE.pinDeckZ - 4.5);
    this._lerpCamera(
      new THREE.Vector3(ballX * 0.3, 1.3, z),
      new THREE.Vector3(ballX * 0.5, 0.4, ballZ + 2.5)
    );
  }
  setCameraPins() {
    this._lerpCamera(
      new THREE.Vector3(0, 1.9, LANE.pinDeckZ - 4.3),
      new THREE.Vector3(0, 0.5, LANE.pinDeckZ + 0.5)
    );
  }
  _lerpCamera(pos, look) {
    this._camTarget = { pos, look };
  }
  _updateCamera(dt) {
    if (!this._camTarget) return;
    const k = 1 - Math.pow(0.001, dt);
    this.camera.position.lerp(this._camTarget.pos, k);
    if (!this._lookAt) this._lookAt = new THREE.Vector3(0, 0.6, 8);
    this._lookAt.lerp(this._camTarget.look, k);
    this.camera.lookAt(this._lookAt);
  }

  // ---------- Lights ----------
  _buildLights() {
    const ambient = new THREE.AmbientLight(0x6678aa, 0.55);
    this.scene.add(ambient);

    const hemi = new THREE.HemisphereLight(0x9fc0ff, 0x141018, 0.6);
    this.scene.add(hemi);

    // Key light over the lane, casts ball/pin shadows.
    const key = new THREE.DirectionalLight(0xfff1d8, 1.15);
    key.position.set(3, 9, 4);
    key.castShadow = true;
    key.shadow.mapSize.set(2048, 2048);
    key.shadow.camera.near = 1;
    key.shadow.camera.far = 40;
    const s = 12;
    key.shadow.camera.left = -s;
    key.shadow.camera.right = s;
    key.shadow.camera.top = 4;
    key.shadow.camera.bottom = -22;
    key.shadow.bias = -0.0004;
    this.scene.add(key);
    this.scene.add(key.target);
    key.target.position.set(0, 0, 9);

    // Pin-deck spotlight for drama.
    const spot = new THREE.SpotLight(0xffffff, 2.2, 14, Math.PI / 6, 0.4, 1.0);
    spot.position.set(0, 6, LANE.pinDeckZ - 2);
    spot.target.position.set(0, 0, LANE.pinDeckZ + 0.5);
    spot.castShadow = true;
    spot.shadow.mapSize.set(1024, 1024);
    this.scene.add(spot);
    this.scene.add(spot.target);

    // Cool fill from behind the bowler.
    const fill = new THREE.PointLight(0x4f7bff, 0.7, 18);
    fill.position.set(0, 3, -4);
    this.scene.add(fill);
  }

  // ---------- Environment ----------
  _buildEnvironment() {
    // Floor of the bowling alley.
    const floorGeo = new THREE.PlaneGeometry(30, 50);
    const floorMat = new THREE.MeshStandardMaterial({
      color: 0x0c1224,
      roughness: 0.9,
      metalness: 0.1,
    });
    const floor = new THREE.Mesh(floorGeo, floorMat);
    floor.rotation.x = -Math.PI / 2;
    floor.position.set(0, -0.02, LANE.length / 2);
    floor.receiveShadow = true;
    this.scene.add(floor);

    // Back wall behind the pins with neon strips.
    const wallMat = new THREE.MeshStandardMaterial({
      color: 0x10142a,
      roughness: 0.7,
      metalness: 0.2,
    });
    const wall = new THREE.Mesh(new THREE.PlaneGeometry(30, 12), wallMat);
    wall.position.set(0, 5, LANE.pinDeckZ + 3.2);
    wall.rotation.y = Math.PI;
    this.scene.add(wall);

    // Neon accent strips on the back wall.
    const neonColors = [0xff4d6d, 0x4fc3ff, 0xffb347];
    neonColors.forEach((c, i) => {
      const strip = new THREE.Mesh(
        new THREE.BoxGeometry(20, 0.12, 0.05),
        new THREE.MeshBasicMaterial({ color: c })
      );
      strip.position.set(0, 2.4 + i * 1.5, LANE.pinDeckZ + 3.15);
      this.scene.add(strip);
    });

    // Pin-setter masking unit above the deck.
    const masking = new THREE.Mesh(
      new THREE.BoxGeometry(LANE.width + 1.2, 2.2, 0.3),
      new THREE.MeshStandardMaterial({ color: 0x07101f, roughness: 0.6, metalness: 0.3 })
    );
    masking.position.set(0, 2.6, LANE.pinDeckZ + 1.2);
    masking.castShadow = true;
    this.scene.add(masking);

    // "STRIKE ZONE" glow bar on the masking unit.
    const bar = new THREE.Mesh(
      new THREE.BoxGeometry(LANE.width + 0.8, 0.5, 0.06),
      new THREE.MeshBasicMaterial({ color: 0xffb347 })
    );
    bar.position.set(0, 2.2, LANE.pinDeckZ + 1.05);
    this.scene.add(bar);
  }

  // ---------- Lane ----------
  _buildLane() {
    const laneLen = LANE.length;
    const laneCenterZ = laneLen / 2;

    // Wood lane surface — procedural plank texture via canvas.
    const tex = this._makeWoodTexture();
    tex.wrapS = THREE.RepeatWrapping;
    tex.wrapT = THREE.RepeatWrapping;
    tex.repeat.set(2, 18);
    tex.anisotropy = this.renderer.capabilities.getMaxAnisotropy();

    const laneMat = new THREE.MeshStandardMaterial({
      map: tex,
      roughness: 0.28,
      metalness: 0.05,
      color: 0xffffff,
    });
    const lane = new THREE.Mesh(
      new THREE.BoxGeometry(LANE.width, 0.08, laneLen + 1.5),
      laneMat
    );
    lane.position.set(0, 0, laneCenterZ - 0.2);
    lane.receiveShadow = true;
    this.scene.add(lane);

    // Oil-shine overlay near the front (subtle gloss patch).
    const oil = new THREE.Mesh(
      new THREE.PlaneGeometry(LANE.width * 0.9, laneLen * 0.55),
      new THREE.MeshStandardMaterial({
        color: 0xffffff,
        roughness: 0.05,
        metalness: 0.0,
        transparent: true,
        opacity: 0.06,
      })
    );
    oil.rotation.x = -Math.PI / 2;
    oil.position.set(0, 0.041, laneLen * 0.3);
    this.scene.add(oil);

    // Aiming arrows (the classic 7 dovetail arrows ~15ft down lane).
    const arrowMat = new THREE.MeshStandardMaterial({
      color: 0x12233f,
      roughness: 0.4,
    });
    for (let i = -3; i <= 3; i++) {
      if (i === 0) continue;
      const a = new THREE.Mesh(new THREE.ConeGeometry(0.035, 0.16, 4), arrowMat);
      a.rotation.x = -Math.PI / 2;
      a.position.set(i * 0.11, 0.045, 5.2 + Math.abs(i) * 0.25);
      this.scene.add(a);
    }
    // Foul-line dots.
    for (let i = -2; i <= 2; i++) {
      const d = new THREE.Mesh(
        new THREE.CircleGeometry(0.022, 12),
        new THREE.MeshStandardMaterial({ color: 0x203a5f })
      );
      d.rotation.x = -Math.PI / 2;
      d.position.set(i * 0.13, 0.043, 0.6);
      this.scene.add(d);
    }

    // Gutters (channels) on each side.
    const gutterMat = new THREE.MeshStandardMaterial({
      color: 0x05080f,
      roughness: 0.5,
      metalness: 0.4,
    });
    const halfW = LANE.width / 2;
    for (const sign of [-1, 1]) {
      const gutter = new THREE.Mesh(
        new THREE.BoxGeometry(0.14, 0.14, laneLen + 1.5),
        gutterMat
      );
      gutter.position.set(sign * (halfW + 0.07), -0.05, laneCenterZ - 0.2);
      gutter.receiveShadow = true;
      this.scene.add(gutter);

      // Side rails.
      const rail = new THREE.Mesh(
        new THREE.BoxGeometry(0.06, 0.18, laneLen + 1.5),
        new THREE.MeshStandardMaterial({ color: 0x1a2440, roughness: 0.5, metalness: 0.3 })
      );
      rail.position.set(sign * (halfW + 0.16), 0.03, laneCenterZ - 0.2);
      this.scene.add(rail);
    }

    // Pin deck (slightly different shade behind the foul of pins).
    const deck = new THREE.Mesh(
      new THREE.BoxGeometry(LANE.width, 0.082, 2.2),
      new THREE.MeshStandardMaterial({ color: 0x2a2118, roughness: 0.35, metalness: 0.05 })
    );
    deck.position.set(0, 0.001, LANE.pinDeckZ + 0.45);
    deck.receiveShadow = true;
    this.scene.add(deck);

    // Pit / back curtain.
    const pit = new THREE.Mesh(
      new THREE.BoxGeometry(LANE.width + 0.5, 1.0, 1.6),
      new THREE.MeshStandardMaterial({ color: 0x02030a, roughness: 1 })
    );
    pit.position.set(0, -0.5, LANE.pinDeckZ + 2.4);
    this.scene.add(pit);
  }

  _makeWoodTexture() {
    const c = document.createElement("canvas");
    c.width = 256;
    c.height = 1024;
    const ctx = c.getContext("2d");
    // Base maple gradient.
    const grd = ctx.createLinearGradient(0, 0, c.width, 0);
    grd.addColorStop(0, "#caa377");
    grd.addColorStop(0.5, "#e3c193");
    grd.addColorStop(1, "#c79a6a");
    ctx.fillStyle = grd;
    ctx.fillRect(0, 0, c.width, c.height);
    // Planks.
    const plankW = c.width / 8;
    for (let i = 0; i <= 8; i++) {
      ctx.strokeStyle = "rgba(80,52,28,0.45)";
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(i * plankW, 0);
      ctx.lineTo(i * plankW, c.height);
      ctx.stroke();
    }
    // Grain.
    ctx.strokeStyle = "rgba(120,82,46,0.18)";
    ctx.lineWidth = 1;
    for (let i = 0; i < 220; i++) {
      const x = Math.random() * c.width;
      const y = Math.random() * c.height;
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineTo(x + (Math.random() - 0.5) * 6, y + 30 + Math.random() * 60);
      ctx.stroke();
    }
    const tex = new THREE.CanvasTexture(c);
    tex.colorSpace = THREE.SRGBColorSpace;
    return tex;
  }

  // ---------- Pins ----------
  _makePinGeometry() {
    // Lathe a bowling-pin silhouette.
    const profile = [
      [0.0, 0.0],
      [0.026, 0.0],
      [0.03, 0.03],
      [0.038, 0.09],
      [0.026, 0.18],
      [0.02, 0.24],
      [0.028, 0.3],
      [0.022, 0.345],
      [0.012, 0.375],
      [0.0, 0.38],
    ];
    const pts = profile.map(([r, y]) => new THREE.Vector2(r, y - PIN_HEIGHT / 2));
    const geo = new THREE.LatheGeometry(pts, 24);
    geo.computeVertexNormals();
    return geo;
  }

  _buildPins() {
    const geo = this._makePinGeometry();
    const bodyMat = new THREE.MeshStandardMaterial({
      color: 0xfaf7f0,
      roughness: 0.32,
      metalness: 0.02,
    });
    const meshes = [];
    for (let i = 0; i < 10; i++) {
      const group = new THREE.Group();
      const body = new THREE.Mesh(geo, bodyMat);
      body.castShadow = true;
      body.receiveShadow = true;
      group.add(body);

      // Red neck stripes.
      const stripeMat = new THREE.MeshStandardMaterial({
        color: 0xd6263a,
        roughness: 0.4,
      });
      const ring1 = new THREE.Mesh(new THREE.TorusGeometry(0.027, 0.006, 8, 24), stripeMat);
      ring1.rotation.x = Math.PI / 2;
      ring1.position.y = 0.07;
      group.add(ring1);
      const ring2 = ring1.clone();
      ring2.position.y = 0.1;
      group.add(ring2);

      this.scene.add(group);
      meshes.push(group);
    }
    return meshes;
  }

  // ---------- Ball ----------
  _buildBall(colorDef) {
    const group = new THREE.Group();
    const geo = new THREE.SphereGeometry(BALL_RADIUS, 48, 48);
    const mat = new THREE.MeshPhysicalMaterial({
      color: colorDef.hex,
      roughness: 0.08,
      metalness: 0.1,
      clearcoat: 1.0,
      clearcoatRoughness: 0.05,
      sheen: 0.4,
      sheenColor: new THREE.Color(colorDef.accent),
    });
    this.ballSphere = new THREE.Mesh(geo, mat);
    this.ballSphere.castShadow = true;
    group.add(this.ballSphere);

    // Finger holes (three small dark dimples on the "top").
    const holeMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.9 });
    const holeGeo = new THREE.CylinderGeometry(0.012, 0.012, 0.05, 12);
    const holePos = [
      [0, BALL_RADIUS - 0.01, 0.02],
      [-0.025, BALL_RADIUS - 0.015, -0.015],
      [0.025, BALL_RADIUS - 0.015, -0.015],
    ];
    for (const [x, y, z] of holePos) {
      const h = new THREE.Mesh(holeGeo, holeMat);
      h.position.set(x, y, z);
      this.ballSphere.add(h);
    }

    this.scene.add(group);
    return group;
  }

  setBallColor(colorDef) {
    this.ballSphere.material.color.set(colorDef.hex);
    this.ballSphere.material.sheenColor.set(colorDef.accent);
  }

  // ---------- Aim arrow (guide) ----------
  _buildAimArrow() {
    const group = new THREE.Group();
    const mat = new THREE.MeshBasicMaterial({
      color: 0xffb347,
      transparent: true,
      opacity: 0.6,
    });
    const shaft = new THREE.Mesh(new THREE.BoxGeometry(0.03, 0.005, 1.6), mat);
    shaft.position.z = 0.8;
    group.add(shaft);
    const head = new THREE.Mesh(new THREE.ConeGeometry(0.06, 0.16, 4), mat);
    head.rotation.x = Math.PI / 2;
    head.position.z = 1.65;
    group.add(head);
    group.visible = false;
    this.scene.add(group);
    return group;
  }

  showAim(x, angle, spin) {
    this.arrow.visible = true;
    this.arrow.position.set(x, 0.05, LANE.approachZ);
    this.arrow.rotation.y = -angle - spin * 0.25;
  }
  hideAim() {
    this.arrow.visible = false;
  }

  // ---------- Frame update ----------
  syncBall(physBall) {
    this.ballMesh.position.set(physBall.pos.x, physBall.pos.y, physBall.pos.z);
    this.ballSphere.rotation.set(
      physBall.rollRot.x,
      physBall.rollRot.y,
      physBall.rollRot.z
    );
  }

  syncPins(pins) {
    for (let i = 0; i < pins.length; i++) {
      const p = pins[i];
      const m = this.pinMeshes[i];
      if (p.removed) {
        m.visible = false;
        continue;
      }
      m.visible = true;
      m.position.set(p.pos.x, p.pos.y, p.pos.z);
      this._tmpE.set(p.tilt.x, p.spinAngle, p.tilt.z, "XYZ");
      m.quaternion.setFromEuler(this._tmpE);
    }
  }

  render(dt) {
    this._updateCamera(dt);
    this.renderer.render(this.scene, this.camera);
  }

  resize() {
    const w = this.canvas.clientWidth || window.innerWidth;
    const h = this.canvas.clientHeight || window.innerHeight;
    this.renderer.setSize(w, h, false);
    this.camera.aspect = w / h;
    this.camera.updateProjectionMatrix();
  }
}

/**
 * input.js — Mouse / touch control for aiming and bowling.
 *
 * Interaction model (designed to be obvious with just a mouse):
 *   - While idle, moving the pointer horizontally aims the ball left/right.
 *   - Press and HOLD, then DRAG the pointer DOWNWARD to wind up power
 *     (further down = more power, shown in the power meter).
 *   - A sideways component of the drag at release imparts SPIN (hook).
 *   - Release to bowl. Releasing with ~zero power cancels.
 *
 * Emits high-level callbacks; it never touches the scene or physics directly.
 */

export class InputController {
  constructor(canvas, handlers) {
    this.canvas = canvas;
    this.handlers = handlers; // { onAim, onCharge, onRelease }
    this.enabled = false;

    this.dragging = false;
    this.startX = 0;
    this.startY = 0;
    this.curX = 0;
    this.curY = 0;

    this.aim = 0; // -1..1 lateral aim
    this.power = 0; // 0..1
    this.spin = 0; // -1..1

    this._bind();
  }

  enable() {
    this.enabled = true;
  }
  disable() {
    this.enabled = false;
    this.dragging = false;
    this.canvas.classList.remove("grabbing");
  }

  _bind() {
    const c = this.canvas;
    c.addEventListener("pointerdown", (e) => this._down(e));
    window.addEventListener("pointermove", (e) => this._move(e));
    window.addEventListener("pointerup", (e) => this._up(e));
    window.addEventListener("pointercancel", () => this._cancel());
  }

  _norm(e) {
    const r = this.canvas.getBoundingClientRect();
    return {
      x: (e.clientX - r.left) / r.width, // 0..1
      y: (e.clientY - r.top) / r.height, // 0..1
    };
  }

  _down(e) {
    if (!this.enabled) return;
    const p = this._norm(e);
    this.dragging = true;
    this.startX = p.x;
    this.startY = p.y;
    this.curX = p.x;
    this.curY = p.y;
    this.power = 0;
    this.spin = 0;
    this.canvas.classList.add("grabbing");
    try {
      this.canvas.setPointerCapture(e.pointerId);
    } catch {}
  }

  _move(e) {
    if (!this.enabled) return;
    const p = this._norm(e);

    if (!this.dragging) {
      // Idle aiming: map horizontal position to aim.
      this.aim = clamp((p.x - 0.5) * 2.0, -1, 1);
      this.handlers.onAim?.(this.aim, this.spin);
      return;
    }

    this.curX = p.x;
    this.curY = p.y;

    // Power from downward drag (drag down to charge).
    const dy = Math.max(0, this.curY - this.startY);
    this.power = clamp(dy / 0.34, 0, 1);

    // Spin from horizontal drag during wind-up.
    const dx = this.curX - this.startX;
    this.spin = clamp(dx * 2.6, -1, 1);

    // Let aim drift a little with the horizontal drag too, so users can
    // fine-tune line while winding up.
    this.aim = clamp(this.aim + dx * 0.04, -1, 1);
    this.startX = this.curX; // incremental aim adjustment

    this.handlers.onCharge?.(this.power, this.aim, this.spin);
  }

  _up() {
    if (!this.enabled || !this.dragging) return;
    this.dragging = false;
    this.canvas.classList.remove("grabbing");

    if (this.power < 0.08) {
      // Treated as a cancel / mis-press.
      this.handlers.onRelease?.(null);
      this.power = 0;
      this.spin = 0;
      return;
    }

    this.handlers.onRelease?.({
      power: this.power,
      aim: this.aim,
      spin: this.spin,
    });
    this.power = 0;
    this.spin = 0;
  }

  _cancel() {
    this.dragging = false;
    this.power = 0;
    this.spin = 0;
    this.canvas.classList.remove("grabbing");
    this.handlers.onRelease?.(null);
  }
}

function clamp(v, lo, hi) {
  return Math.max(lo, Math.min(hi, v));
}

/**
 * ui.js — DOM heads-up display: scoreboard, control meters, banners, ball
 * picker and start/gameover screens. Pure presentation; the game core calls
 * these methods and never reads the DOM itself.
 */

import { BALL_COLORS } from "./scene.js";

export class GameUI {
  constructor() {
    this.el = {
      loading: document.getElementById("loading"),
      startScreen: document.getElementById("start-screen"),
      gameoverScreen: document.getElementById("gameover-screen"),
      scoreboard: document.getElementById("scoreboard"),
      controls: document.getElementById("controls"),
      banner: document.getElementById("banner"),
      ballPicker: document.getElementById("ball-picker"),
      sbFrames: document.getElementById("sb-frames"),
      sbTotal: document.getElementById("sb-total-value"),
      aimFill: document.getElementById("aim-fill"),
      aimMarker: document.getElementById("aim-marker"),
      spinFill: document.getElementById("spin-fill"),
      spinMarker: document.getElementById("spin-marker"),
      powerFill: document.getElementById("power-fill"),
      ctrlHint: document.getElementById("ctrl-hint"),
      bpSwatches: document.getElementById("bp-swatches"),
      finalScore: document.getElementById("final-score"),
      finalMsg: document.getElementById("final-msg"),
      startBtn: document.getElementById("start-btn"),
      replayBtn: document.getElementById("replay-btn"),
    };
    this._buildFrames();
    this._buildSwatches();
    this._bannerTimer = null;
  }

  hideLoading() {
    this.el.loading.classList.add("hidden");
  }
  showStart() {
    this.el.startScreen.classList.remove("hidden");
  }
  hideStart() {
    this.el.startScreen.classList.add("hidden");
  }

  showGame() {
    this.el.scoreboard.classList.remove("hidden");
    this.el.controls.classList.remove("hidden");
    this.el.ballPicker.classList.remove("hidden");
  }
  hideGame() {
    this.el.scoreboard.classList.add("hidden");
    this.el.controls.classList.add("hidden");
    this.el.ballPicker.classList.add("hidden");
  }

  onStart(cb) {
    this.el.startBtn.addEventListener("click", cb);
  }
  onReplay(cb) {
    this.el.replayBtn.addEventListener("click", cb);
  }
  onPickBall(cb) {
    this._pickCb = cb;
  }

  // ---------- Scoreboard ----------
  _buildFrames() {
    this.el.sbFrames.innerHTML = "";
    this.frameEls = [];
    for (let f = 0; f < 10; f++) {
      const isTenth = f === 9;
      const frame = document.createElement("div");
      frame.className = "frame" + (isTenth ? " tenth" : "");
      const num = document.createElement("div");
      num.className = "frame-num";
      num.textContent = f + 1;
      const rolls = document.createElement("div");
      rolls.className = "frame-rolls";
      const boxCount = isTenth ? 3 : 2;
      const rollEls = [];
      for (let b = 0; b < boxCount; b++) {
        const r = document.createElement("div");
        r.className = "roll";
        rolls.appendChild(r);
        rollEls.push(r);
      }
      const score = document.createElement("div");
      score.className = "frame-score";
      frame.appendChild(num);
      frame.appendChild(rolls);
      frame.appendChild(score);
      this.el.sbFrames.appendChild(frame);
      this.frameEls.push({ frame, rollEls, score });
    }
  }

  renderScorecard(scorecard, activeFrame, total) {
    scorecard.forEach((fr, idx) => {
      const fe = this.frameEls[idx];
      fe.frame.classList.toggle("active", idx === activeFrame);

      const isTenth = idx === 9;
      const boxes = fe.rollEls;
      boxes.forEach((b) => {
        b.textContent = "";
        b.className = "roll";
      });

      if (isTenth) {
        fr.symbols.forEach((sym, i) => {
          if (i < boxes.length) {
            boxes[i].textContent = sym;
            if (sym === "X") boxes[i].classList.add("strike");
            else if (sym === "/") boxes[i].classList.add("spare");
          }
        });
      } else {
        // Normal frame: strike shows in the second box, leaving first blank.
        if (fr.symbols[1] === "X") {
          boxes[0].textContent = "";
          boxes[1].textContent = "X";
          boxes[1].classList.add("strike");
        } else {
          if (fr.symbols[0] !== undefined && fr.symbols[0] !== "") {
            boxes[0].textContent = fr.symbols[0];
          }
          if (fr.symbols[1]) {
            boxes[1].textContent = fr.symbols[1];
            if (fr.symbols[1] === "/") boxes[1].classList.add("spare");
          }
        }
      }

      fe.score.textContent = fr.cumulative !== null && fr.cumulative !== undefined ? fr.cumulative : "";
    });
    this.el.sbTotal.textContent = total;
  }

  // ---------- Control meters ----------
  updateAim(aim, spin) {
    // aim -1..1 → marker position 0..100%
    const pct = (aim + 1) / 2 * 100;
    this.el.aimMarker.style.left = pct + "%";
    this.el.aimFill.style.width = pct + "%";
    this._updateSpin(spin);
  }
  updateCharge(power, aim, spin) {
    this.el.powerFill.style.width = Math.round(power * 100) + "%";
    const pct = (aim + 1) / 2 * 100;
    this.el.aimMarker.style.left = pct + "%";
    this.el.aimFill.style.width = pct + "%";
    this._updateSpin(spin);
  }
  _updateSpin(spin) {
    // Center at 50%, fill left/right based on sign.
    const mid = 50;
    const pct = mid + (spin * 50);
    this.el.spinMarker.style.left = clamp(pct, 2, 98) + "%";
    if (spin >= 0) {
      this.el.spinFill.style.left = "50%";
      this.el.spinFill.style.width = Math.abs(spin) * 50 + "%";
    } else {
      this.el.spinFill.style.left = 50 - Math.abs(spin) * 50 + "%";
      this.el.spinFill.style.width = Math.abs(spin) * 50 + "%";
    }
  }
  resetPower() {
    this.el.powerFill.style.width = "0%";
  }
  setHint(text) {
    this.el.ctrlHint.textContent = text;
  }

  // ---------- Banner ----------
  showBanner(text, kind = "") {
    const b = this.el.banner;
    b.textContent = text;
    b.className = "banner";
    if (kind) b.classList.add(kind);
    // Force reflow so the animation restarts.
    void b.offsetWidth;
    b.classList.add("show");
    b.classList.remove("hidden");
    clearTimeout(this._bannerTimer);
    this._bannerTimer = setTimeout(() => {
      b.classList.remove("show");
    }, 1850);
  }

  // ---------- Ball picker ----------
  _buildSwatches() {
    this.el.bpSwatches.innerHTML = "";
    this.swatchEls = [];
    BALL_COLORS.forEach((c, i) => {
      const s = document.createElement("div");
      s.className = "swatch" + (i === 0 ? " selected" : "");
      s.style.background = `radial-gradient(circle at 35% 30%, #${c.accent
        .toString(16)
        .padStart(6, "0")}, #${c.hex.toString(16).padStart(6, "0")})`;
      s.title = c.name;
      s.addEventListener("click", () => {
        this.swatchEls.forEach((e) => e.classList.remove("selected"));
        s.classList.add("selected");
        this._pickCb?.(i);
      });
      this.el.bpSwatches.appendChild(s);
      this.swatchEls.push(s);
    });
  }

  // ---------- Game over ----------
  showGameOver(total) {
    this.el.finalScore.textContent = `Final score: ${total}`;
    this.el.finalMsg.textContent = ratingMessage(total);
    this.el.gameoverScreen.classList.remove("hidden");
  }
  hideGameOver() {
    this.el.gameoverScreen.classList.add("hidden");
  }
}

function ratingMessage(total) {
  if (total === 300) return "A PERFECT GAME. You are a legend.";
  if (total >= 250) return "Phenomenal — pro-level bowling!";
  if (total >= 200) return "Excellent! You broke 200.";
  if (total >= 150) return "Solid game. Above average!";
  if (total >= 100) return "Nice — you cracked triple digits.";
  if (total >= 70) return "Good effort. Keep practicing!";
  return "Everyone starts somewhere. Roll again!";
}

function clamp(v, lo, hi) {
  return Math.max(lo, Math.min(hi, v));
}

/**
 * main.js — Game orchestrator.
 *
 * Wires together the renderer (scene.js), the physics simulator (physics.js),
 * the scoring engine (scoring.js), input (input.js) and the HUD (ui.js), and
 * drives the fixed-step game loop plus a small state machine:
 *
 *   AIMING → ROLLING → SETTLING → (next ball | next frame | game over)
 *
 * Camera, banners and pin re-racking all hang off these transitions.
 */

import { BowlingScene, BALL_COLORS } from "./scene.js";
import { BowlingPhysics, LANE, BALL_RADIUS } from "./physics.js";
import { BowlingGame } from "./scoring.js";
import { InputController } from "./input.js";
import { GameUI } from "./ui.js";

const State = {
  AIMING: "AIMING",
  ROLLING: "ROLLING",
  SETTLING: "SETTLING",
  RESETTING: "RESETTING",
  GAMEOVER: "GAMEOVER",
};

class BowlingApp {
  constructor() {
    this.canvas = document.getElementById("scene");
    this.scene = new BowlingScene(this.canvas);
    this.physics = new BowlingPhysics();
    this.game = new BowlingGame();
    this.ui = new GameUI();

    this.state = State.AIMING;
    this.ballColorIndex = 0;
    this.pinsBeforeRoll = 10;
    this.resetTimer = 0;

    this.input = new InputController(this.canvas, {
      onAim: (aim, spin) => this._onAim(aim, spin),
      onCharge: (power, aim, spin) => this._onCharge(power, aim, spin),
      onRelease: (shot) => this._onRelease(shot),
    });

    this.ui.onStart(() => this._startGame());
    this.ui.onReplay(() => this._startGame());
    this.ui.onPickBall((i) => {
      this.ballColorIndex = i;
      this.scene.setBallColor(BALL_COLORS[i]);
    });

    this.currentAim = 0;
    this.currentSpin = 0;

    this.last = performance.now();
    this.acc = 0;
    this.fixedDt = 1 / 120;

    this._loop = this._loop.bind(this);
  }

  init() {
    // First render + show the start screen once the GPU is warm.
    this.scene.syncPins(this.physics.pins);
    this.scene.syncBall(this.physics.ball);
    this.scene.render(0.016);
    requestAnimationFrame(() => {
      this.ui.hideLoading();
      this.ui.showStart();
      requestAnimationFrame(this._loop);
    });
  }

  _startGame() {
    this.ui.hideStart();
    this.ui.hideGameOver();
    this.game.reset();
    this.physics.rackFull();
    this.physics.resetBall(0);
    this.state = State.AIMING;
    this.pinsBeforeRoll = 0;
    this.currentAim = 0;
    this.currentSpin = 0;
    this.scene.setBallColor(BALL_COLORS[this.ballColorIndex]);
    this.scene.setCameraBowler();
    this.ui.showGame();
    this.ui.resetPower();
    this.ui.setHint("Drag the ball back & release to bowl. Move to aim.");
    this._refreshScoreboard();
    this.input.enable();
    this._positionBallForAim(0);
    this.scene.showAim(0, 0, 0);
  }

  // ---------- Input handlers ----------
  _onAim(aim, spin) {
    if (this.state !== State.AIMING) return;
    this.currentAim = aim;
    const x = aim * (LANE.width / 2 - BALL_RADIUS - 0.02);
    this._positionBallForAim(x);
    this.scene.showAim(x, aim * 0.06, this.currentSpin);
    this.ui.updateAim(aim, this.currentSpin);
  }

  _onCharge(power, aim, spin) {
    if (this.state !== State.AIMING) return;
    this.currentAim = aim;
    this.currentSpin = spin;
    const x = aim * (LANE.width / 2 - BALL_RADIUS - 0.02);
    this._positionBallForAim(x);
    this.scene.showAim(x, aim * 0.06, spin);
    this.ui.updateCharge(power, aim, spin);
    this.ui.setHint(
      power > 0.85 ? "Let it rip!" : "Drag further for power · flick sideways for spin"
    );
  }

  _onRelease(shot) {
    if (this.state !== State.AIMING) return;
    if (!shot) {
      this.ui.resetPower();
      this.ui.setHint("Drag the ball back & release to bowl.");
      return;
    }
    this.input.disable();
    this.scene.hideAim();
    this.ui.resetPower();

    const aimX = shot.aim * (LANE.width / 2 - BALL_RADIUS - 0.02);
    const angle = shot.aim * 0.05; // slight initial heading from aim
    this.pinsBeforeRoll = this.physics.countDownPins();

    this.physics.launch({
      power: shot.power,
      aimX,
      angle,
      spin: shot.spin * 0.85,
    });
    this.state = State.ROLLING;
    this.ui.setHint("");
  }

  _positionBallForAim(x) {
    if (this.physics.rolling) return;
    this.physics.ball.pos.x = x;
    this.physics.ball.pos.y = BALL_RADIUS;
    this.physics.ball.pos.z = LANE.approachZ - 0.4;
    this.physics.ball.rollRot.x = 0;
    this.scene.syncBall(this.physics.ball);
  }

  // ---------- Main loop ----------
  _loop(now) {
    const dtRaw = Math.min((now - this.last) / 1000, 0.05);
    this.last = now;

    if (this.state === State.ROLLING) {
      this.acc += dtRaw;
      while (this.acc >= this.fixedDt) {
        this.physics.step(this.fixedDt);
        this.acc -= this.fixedDt;
      }
      this.scene.syncBall(this.physics.ball);
      this.scene.syncPins(this.physics.pins);

      // Camera follows the ball, then swings to the pins near the deck.
      const bz = this.physics.ball.pos.z;
      if (bz > LANE.pinDeckZ - 6) {
        this.scene.setCameraPins();
      } else {
        this.scene.setCameraFollow(bz, this.physics.ball.pos.x);
      }

      if (this.physics.isSettled()) {
        this.physics.endRoll();
        this.state = State.SETTLING;
        this.settleHold = 0;
      }
    } else if (this.state === State.SETTLING) {
      this.settleHold += dtRaw;
      // brief pause to admire the result before scoring
      if (this.settleHold > 0.4) {
        this._scoreRoll();
      }
    } else if (this.state === State.RESETTING) {
      this.resetTimer -= dtRaw;
      if (this.resetTimer <= 0) {
        this._beginNextBall();
      }
    }

    this.scene.render(dtRaw);
    requestAnimationFrame(this._loop);
  }

  // ---------- Scoring a completed roll ----------
  _scoreRoll() {
    const downNow = this.physics.countDownPins();
    const knockedThisRoll = Math.max(0, downNow - this.pinsBeforeRoll);

    const result = this.game.roll(knockedThisRoll);
    this._refreshScoreboard();

    // Celebratory banners.
    if (result.isStrike) {
      this.scene.setCameraPins();
      this.ui.showBanner("STRIKE!", "strike");
    } else if (result.isSpare) {
      this.ui.showBanner("SPARE!", "spare");
    } else if (knockedThisRoll === 0 && this.physics.ballInGutter) {
      this.ui.showBanner("GUTTER", "");
    } else if (knockedThisRoll === 0) {
      this.ui.showBanner("MISS", "");
    } else if (this.game.isFirstBallOfFrame() === false && !result.frameComplete) {
      // mid-frame: small numeric feedback only via scoreboard
    }

    if (result.gameComplete) {
      this.state = State.RESETTING;
      this.resetTimer = 2.0;
      this._gameWillEnd = true;
      return;
    }

    // Decide pin reset behaviour for the next ball.
    this._nextResetPins = result.resetPins;
    this.state = State.RESETTING;
    this.resetTimer = result.resetPins ? 1.8 : 1.4;
  }

  _beginNextBall() {
    if (this._gameWillEnd) {
      this._gameWillEnd = false;
      this._endGame();
      return;
    }

    if (this._nextResetPins) {
      this.physics.rackFull();
    } else {
      // Sweep away the deadwood, keep standing pins.
      this.physics.clearKnockedPins();
    }
    this._nextResetPins = false;

    this.currentAim = 0;
    this.currentSpin = 0;
    this.physics.resetBall(0);
    this._positionBallForAim(0);
    this.scene.syncPins(this.physics.pins);
    this.scene.setCameraBowler();
    this.scene.showAim(0, 0, 0);
    this.ui.updateAim(0, 0);
    this.ui.setHint(
      this.game.isFirstBallOfFrame()
        ? "New frame — knock 'em all down!"
        : "Pick up the spare!"
    );
    this.state = State.AIMING;
    this.input.enable();
    this._refreshScoreboard();
  }

  _endGame() {
    this.state = State.GAMEOVER;
    this.input.disable();
    const total = this.game.getTotal();
    this.scene.setCameraPins();
    this.ui.showGameOver(total);
  }

  _refreshScoreboard() {
    const card = this.game.getScorecard();
    const total = this.game.getTotal();
    const active = Math.min(this.game.currentFrame, 9);
    this.ui.renderScorecard(card, active, total);
  }
}

// Boot.
const app = new BowlingApp();
app.init();

// Expose for debugging in the console.
window.__bowling = app;

