function play(rolls) {
  const g = new BowlingGame();
  for (const r of rolls) g.roll(r);
  return g;
}

let pass = 0, fail = 0;
function check(name, got, want) {
  if (got === want) { pass++; }
  else { fail++; console.log(`FAIL ${name}: got ${got}, want ${want}`); }
}

// Perfect game: 12 strikes = 300
const perfect = play(Array(12).fill(10));
check("perfect game total", perfect.getTotal(), 300);
check("perfect game complete", perfect.complete, true);

// All gutters = 0
const gutter = play(Array(20).fill(0));
check("all gutters total", gutter.getTotal(), 0);
check("gutter complete", gutter.complete, true);

// All 9s with miss (9,0 x10) = 90
const nines = play(Array(10).fill(0).flatMap(() => [9, 0]));
check("all nine-miss total", nines.getTotal(), 90);

// All spares with 5s, plus bonus 5 = each frame 15, last 15 = 150
const spares = play([...Array(10).fill(0).flatMap(() => [5,5]), 5]);
check("all fives spare total", spares.getTotal(), 150);

// Known mixed game from Wikipedia-style example:
// Frame: 1/(strike), then specific
// Use a classic: rolls 10,7,3,9,0,10,0,8,8,2,0,6,10,10,10,8,1 -> compute reference
// Simpler verified scenario: single strike then 4,2 -> frame1 = 10+4+2=16, frame2=6 => 22 after 2 frames, rest open
const g3 = play([10, 4, 2, 3, 4, ...Array(14).fill(0)]);
// frame1: 10+4+2 = 16; frame2: 4+2=6 -> cum 22; frame3: 3+4=7 -> cum 29; remaining 0
check("strike+open total", g3.getTotal(), 29);

// Spare then strike: 5,5,10,0,0 ... frame1 spare = 10+10=20, frame2 strike=10+0+0=10
const g4 = play([5,5, 10, 0,0, ...Array(12).fill(0)]);
check("spare then strike total", g4.getTotal(), 40);

// Tenth frame strike gets two bonus balls: nine open frames of 0, then X,X,X in tenth = 30
const g5 = play([...Array(18).fill(0), 10,10,10]);
check("tenth all strikes", g5.getTotal(), 30);
check("tenth all strikes complete", g5.complete, true);

// Tenth frame spare gets one bonus: 0s then 5,5,7 = 17
const g6 = play([...Array(18).fill(0), 5,5,7]);
check("tenth spare bonus", g6.getTotal(), 17);
check("tenth spare complete", g6.complete, true);

// Tenth open frame ends after 2 balls: 0s then 3,4 = 7
const g7 = play([...Array(18).fill(0), 3,4]);
check("tenth open ends at 2", g7.getTotal(), 7);
check("tenth open complete", g7.complete, true);

// Scorecard cumulative correctness for perfect game frame-by-frame (30,60,...300)
const card = perfect.getScorecard();
check("perfect frame1 cum", card[0].cumulative, 30);
check("perfect frame5 cum", card[4].cumulative, 150);
check("perfect frame10 cum", card[9].cumulative, 300);

// Incomplete frame leaves cumulative null
const g8 = play([3]);
const c8 = g8.getScorecard();
check("incomplete frame cum null", c8[0].cumulative, null);

console.log(`\n${pass} passed, ${fail} failed`);
process.exit(fail ? 1 : 0);
'

