import { BowlingPhysics } from "./physics.js";
const dt = 1/120;
function run(opts){
  const p = new BowlingPhysics(); p.rackFull(); p.launch(opts);
  let s=0; while(!p.isSettled() && s<3000){ p.step(dt); s++; }
  return p.countDownPins();
}
function dist(opts, n=50){ const h={}; let tot=0,strikes=0; for(let i=0;i<n;i++){const d=run(opts); h[d]=(h[d]||0)+1; tot+=d; if(d===10)strikes++;} return {avg:+(tot/n).toFixed(1), strikes:`${strikes}/${n}`, dist:h}; }
