function play(rolls){const g=new BowlingGame();for(const r of rolls)g.roll(r);return g;}
let pass=0,fail=0;
function check(n,got,want){ if(JSON.stringify(got)===JSON.stringify(want)){pass++;}else{fail++;console.log(`FAIL ${n}: got ${JSON.stringify(got)} want ${JSON.stringify(want)}`);} }

// A realistic full game (a known 167 sample):
// X 7/ 72 9/ X X 80 8/ 9/ X72
// Compute manually:
// f1 X = 10 + 7 + 3 = 20  -> 20
// f2 7/ = 10 + 7 = 17     -> 37
// f3 72 = 9               -> 46
// f4 9/ = 10 + 10 = 20    -> 66  (next ball f5 strike=10)
// f5 X = 10 + 10 + 8 = 28 -> 94
// f6 X = 10 + 8 + 0 = 18  -> 112
// f7 80 = 8               -> 120
// f8 8/ = 10 + 9 = 19     -> 139
// f9 9/ = 10 + 10 = 20    -> 159 (f10 first ball X=10)
// f10 X 7 2 = 19          -> 178
const g = play([10, 7,3, 7,2, 9,1, 10, 10, 8,0, 8,2, 9,1, 10,7,2]);
const card = g.getScorecard();
check("realistic total", g.getTotal(), 178);
check("f1 cum", card[0].cumulative, 20);
check("f5 cum", card[4].cumulative, 94);
check("f9 cum", card[8].cumulative, 159);
check("f10 cum", card[9].cumulative, 178);
check("game complete", g.complete, true);

// 10th frame: strike then open (X then 4,3) - bonus = 4+3
// 9 zeros frames then X 4 3 = 17 in tenth
const g2 = play([...Array(18).fill(0), 10, 4, 3]);
check("10th strike+open", g2.getTotal(), 17);
check("10th strike+open complete", g2.complete, true);

// 10th: two strikes then non-strike (X X 5) = 25
const g3 = play([...Array(18).fill(0), 10, 10, 5]);
check("10th X X 5", g3.getTotal(), 25);

// Pins-remaining tracking after a non-strike first ball
const g4 = new BowlingGame();
g4.roll(6);
check("pins remaining after 6", g4.pinsRemaining, 4);
check("is second ball", g4.isFirstBallOfFrame(), false);

console.log(`\n${pass} passed, ${fail} failed`);
process.exit(fail?1:0);
